<?php
 namespace League\CommonMark\Reference; use League\CommonMark\Cursor; use League\CommonMark\Util\LinkParserHelper; final class ReferenceParser { private $referenceMap; public function __construct(ReferenceMapInterface $referenceMap) { $this->referenceMap = $referenceMap; } public function parse(Cursor $cursor) { if ($cursor->isAtEnd()) { return false; } $initialState = $cursor->saveState(); $matchChars = LinkParserHelper::parseLinkLabel($cursor); if ($matchChars === 0) { $cursor->restoreState($initialState); return false; } $label = \substr($cursor->getPreviousText(), 1, -1); if (\preg_match('/[^\s]/', $label) === 0) { $cursor->restoreState($initialState); return false; } if ($cursor->getCharacter() !== ':') { $cursor->restoreState($initialState); return false; } $cursor->advanceBy(1); $cursor->advanceToNextNonSpaceOrNewline(); $destination = LinkParserHelper::parseLinkDestination($cursor); if ($destination === null) { $cursor->restoreState($initialState); return false; } $previousState = $cursor->saveState(); if ($cursor->advanceToNextNonSpaceOrNewline() > 0) { $title = LinkParserHelper::parseLinkTitle($cursor); } if (!isset($title)) { $title = ''; $cursor->restoreState($previousState); } $atLineEnd = true; if ($cursor->match('/^ *(?:\n|$)/') === null) { if ($title === '') { $atLineEnd = false; } else { $title = ''; $cursor->restoreState($previousState); $atLineEnd = $cursor->match('/^ *(?:\n|$)/') !== null; } } if (!$atLineEnd) { $cursor->restoreState($initialState); return false; } if (!$this->referenceMap->contains($label)) { $reference = new Reference($label, $destination, $title); $this->referenceMap->addReference($reference); } return true; } } 